<style id="wp-block-template-skip-link-inline-css">.skip-link.screen-reader-text {
			border: 0;
			clip-path: inset(50%);
			height: 1px;
			margin: -1px;
			overflow: hidden;
			padding: 0;
			position: absolute !important;
			width: 1px;
			word-wrap: normal !important;
		}

		.skip-link.screen-reader-text:focus {
			background-color: #eee;
			clip-path: none;
			color: #444;
			display: block;
			font-size: 1em;
			height: auto;
			left: 5px;
			line-height: normal;
			padding: 15px 23px 14px;
			text-decoration: none;
			top: 5px;
			width: auto;
			z-index: 100000;
		}/* --- HEADER: force proper layout on mobile --- */
@media (max-width: 600px) {
  /* Your header columns wrapper (the one you clicked in DevTools) */
  .wp-block-columns.inner-menu-header {
    display: grid !important;
    grid-template-columns: auto 1fr auto;   /* logo | space/title | hamburger */
    align-items: center !important;
    gap: .5rem !important;
    position: relative;
    z-index: 10;
  }
  .wp-block-columns.inner-menu-header .wp-block-column:first-child { justify-self: start; }
  .wp-block-columns.inner-menu-header .wp-block-column:nth-child(2) { justify-self: center; }
  .wp-block-columns.inner-menu-header .wp-block-column:last-child  { justify-self: end; }

  /* WP Nav hamburger button */
  button.wp-block-navigation__responsive-container-open {
    margin: 0 !important;
    line-height: 1 !important;
  }
}

/* --- HERO/TITLE: prevent clipping & scale text --- */
@media (max-width: 600px) {
  /* Make cover block expand instead of clipping */
  .wp-block-cover {
    min-height: initial !important;
    height: auto !important;
    padding: 24px 16px !important;
    overflow: visible !important;
  }

  /* Scale heading inside the cover */
  .wp-block-cover .wp-block-cover__inner-container h1,
  .wp-block-cover .wp-block-cover__inner-container .wp-block-heading,
  .wp-block-cover .wp-block-cover__inner-container .has-large-font-size,
  .wp-block-cover .wp-block-cover__inner-container .has-larger-font-size {
    font-size: clamp(20px, 6vw, 28px) !important;
    line-height: 1.15 !important;
    text-align: center !important;
    word-break: break-word !important;
    white-space: normal !important;
    margin: 0 !important;
  }
}

/* --- General guardrails so columns don't squash text --- */
@media (max-width: 600px) {
  .wp-block-columns { flex-wrap: wrap !important; }
  .wp-block-column  { min-width: 0 !important; }
}
</style>
